import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums) {
        int n = nums.length;
        int maxIndex = n - 1;
        boolean[] isPrime = new boolean[maxIndex + 1];
        Arrays.fill(isPrime, true);
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i <= (int) Math.sqrt(maxIndex); i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= maxIndex; j += i) {
                    isPrime[j] = false;
                }
            }
        }
        long sumA = 0;
        long sumB = 0;
        for (int i = 0; i < n; i++) {
            if (isPrime[i]) {
                sumA += nums[i];
            } else {
                sumB += nums[i];
            }
        }
        return Math.abs(sumA - sumB);
    }
}
```

